// // This module selects between two 5-bit inputs based on a single-bit control signal.
// When 'choose' is 0, 'out' equals 'in1'; when 'choose' is 1, 'out' equals 'in2'.
// For any other value of 'choose', 'out' is set to all ones.
module select2_5(
    input [4:0] in1,
    input [4:0] in2,
    input choose,
    output reg [4:0] out
);

    always@(in1 or in2 or choose)
    case(choose)
        1'b0: out = in1;
        1'b1: out = in2;
        default: out = 5'b0;
    endcase

endmodule

